import React, { useEffect, useState } from 'react'
import { farmService } from '../../services/api'
import '../../styles/dashboard.css'

const emptyForm = {
  farm_name: '',
  location: '',
  area_hectare: '',
}

const formatRoundedNumber = (value) => {
  if (value === null || value === undefined || value === '') return '-'
  const numberValue = Number(value)
  if (Number.isNaN(numberValue)) return value
  return String(Math.round(numberValue))
}

const OwnerFarms = () => {
  const [farms, setFarms] = useState([])
  const [loading, setLoading] = useState(true)
  const [saving, setSaving] = useState(false)
  const [error, setError] = useState('')
  const [showModal, setShowModal] = useState(false)
  const [editingFarm, setEditingFarm] = useState(null)
  const [form, setForm] = useState(emptyForm)

  useEffect(() => {
    fetchData()
  }, [])

  const fetchData = async () => {
    try {
      setLoading(true)
      const res = await farmService.getFarms()
      setFarms(res?.data?.data || [])
      setError('')
    } catch (err) {
      setError(err?.response?.data?.message || 'Không tải được dữ liệu trại nuôi')
    } finally {
      setLoading(false)
    }
  }

  const openCreateModal = () => {
    setEditingFarm(null)
    setForm(emptyForm)
    setShowModal(true)
  }

  const openEditModal = (farm) => {
    setEditingFarm(farm)
    setForm({
      farm_name: farm.farm_name || '',
      location: farm.location || '',
      area_hectare: farm.area_hectare ?? '',
    })
    setShowModal(true)
  }

  const handleChange = (field, value) => {
    setForm((prev) => ({ ...prev, [field]: value }))
  }

  const handleSubmit = async (event) => {
    event.preventDefault()
    try {
      setSaving(true)
      const payload = {
        farm_name: form.farm_name.trim(),
        location: form.location.trim() || null,
        area_hectare: form.area_hectare ? Number(form.area_hectare) : null,
      }

      if (editingFarm) {
        await farmService.updateFarm(editingFarm.farm_id, payload)
      } else {
        await farmService.createFarm(payload)
      }

      setShowModal(false)
      setEditingFarm(null)
      setForm(emptyForm)
      await fetchData()
    } catch (err) {
      setError(err?.response?.data?.message || 'Không lưu được trại nuôi')
    } finally {
      setSaving(false)
    }
  }

  const handleDelete = async (farmId) => {
    if (!window.confirm('Xóa trại này?')) return
    try {
      await farmService.deleteFarm(farmId)
      await fetchData()
    } catch (err) {
      setError(err?.response?.data?.message || 'Không xóa được trại')
    }
  }

  return (
    <div className="dashboard-container">
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 20 }}>
        <div>
          <h2>Quản lý trại nuôi</h2>
          <p style={{ margin: 0, color: '#666' }}>Tạo, cập nhật trại và quản lý thông tin.</p>
        </div>
        <button className="btn btn-primary" onClick={openCreateModal}>
          + Tạo trại mới
        </button>
      </div>

      {error && <div className="alert alert-danger">{error}</div>}

      <div className="card">
        <h3>Danh sách trại</h3>
        <div className="table-responsive">
          <table className="table">
            <thead>
              <tr>
                <th>Mã trại</th>
                <th>Tên trại</th>
                <th>Địa điểm</th>
                <th>Diện tích (ha)</th>
                <th>Trạng thái</th>
                <th>Hành động</th>
              </tr>
            </thead>
            <tbody>
              {loading ? (
                <tr><td colSpan="6">Đang tải...</td></tr>
              ) : farms.length === 0 ? (
                <tr><td colSpan="6">Chưa có trại nào</td></tr>
              ) : (
                farms.map((farm) => (
                  <tr key={farm.farm_id}>
                    <td>{farm.farm_code}</td>
                    <td>{farm.farm_name}</td>
                    <td>{farm.location || '-'}</td>
                    <td>{formatRoundedNumber(farm.area_hectare)}</td>
                    <td>{farm.status || 'ACTIVE'}</td>
                    <td style={{ display: 'flex', gap: 8 }}>
                      <button className="btn btn-secondary" onClick={() => openEditModal(farm)}>Sửa</button>
                      <button className="btn btn-danger" onClick={() => handleDelete(farm.farm_id)}>Xóa</button>
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>
      </div>

      {showModal && (
        <div className="modal" onClick={() => setShowModal(false)}>
          <div className="modal-content" onClick={(e) => e.stopPropagation()} style={{ maxWidth: 720 }}>
            <h3 style={{ marginTop: 0 }}>{editingFarm ? 'Cập nhật trại' : 'Tạo trại mới'}</h3>
            <form onSubmit={handleSubmit}>
              <div className="form-group">
                <label>Tên trại</label>
                <input className="input" value={form.farm_name} onChange={(e) => handleChange('farm_name', e.target.value)} required />
              </div>

              <div style={{ display: 'grid', gridTemplateColumns: 'repeat(2, 1fr)', gap: 12 }}>
                <div className="form-group">
                  <label>Địa điểm</label>
                  <input className="input" value={form.location} onChange={(e) => handleChange('location', e.target.value)} />
                </div>
                <div className="form-group">
                  <label>Diện tích (ha)</label>
                  <input className="input" type="number" value={form.area_hectare} onChange={(e) => handleChange('area_hectare', e.target.value)} />
                </div>
              </div>

              <div style={{ display: 'flex', gap: '10px', marginTop: '20px' }}>
                <button type="submit" className="btn btn-primary" style={{ flex: 1 }} disabled={saving}>
                  💾 {saving ? 'Đang lưu' : 'Lưu'}
                </button>
                <button type="button" className="btn btn-secondary" style={{ flex: 1 }} onClick={() => setShowModal(false)}>
                  ❌ Hủy
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  )
}

export default OwnerFarms
